import { t } from './l10n.js'
import { formatMoney } from './currency.js'

export function formatSize(bytes) {
	if (!bytes && bytes !== 0) {
		return '—'
	}
	if (bytes < 1024) {
		return bytes + ' B'
	}
	if (bytes < 1024 * 1024) {
		return (bytes / 1024).toFixed(1) + ' KB'
	}
	if (bytes < 1024 * 1024 * 1024) {
		return (bytes / (1024 * 1024)).toFixed(1) + ' MB'
	}
	return (bytes / (1024 * 1024 * 1024)).toFixed(2) + ' GB'
}

export function formatRelativeDate(ms) {
	if (!ms) {
		return '—'
	}
	try {
		const diff = Date.now() - ms
		const days = Math.floor(diff / 86400000)
		if (days < 1) {
			return t('Today')
		}
		return days + t(' days ago')
	} catch {
		return '—'
	}
}

export function formatShareDate(ms) {
	if (!ms) {
		return '—'
	}
	try {
		const d = new Date(ms)
		const pad = (n) => String(n).padStart(2, '0')
		return d.getFullYear() + '/'
			+ pad(d.getMonth() + 1) + '/'
			+ pad(d.getDate()) + ' '
			+ pad(d.getHours()) + ':'
			+ pad(d.getMinutes())
	} catch {
		return '—'
	}
}

/** 将 API 返回的相对路径转为可分享的完整 URL */
export function buildPublicUrl(path) {
	if (!path) {
		return ''
	}
	if (/^https?:\/\//i.test(path)) {
		return path
	}
	const origin = typeof window !== 'undefined' && window.location?.origin
		? window.location.origin
		: ''
	if (!origin) {
		return path
	}
	return origin + (path.startsWith('/') ? path : '/' + path)
}

/** @deprecated Use formatMoney */
export function formatPriceYuan(cents) {
	return formatMoney(cents)
}

export function formatNavCounter(value) {
	const n = Number(value)
	if (!n || n <= 0) {
		return 0
	}
	return n > 999 ? 999 : n
}
